import{_ as a,o as i,c as n,ag as l}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Alineación","description":"","frontmatter":{},"headers":[],"relativePath":"es/industrial-practices/installation-mounting/alignment.md","filePath":"es/industrial-practices/installation-mounting/alignment.md"}'),o={name:"es/industrial-practices/installation-mounting/alignment.md"};function s(c,e,r,t,d,p){return i(),n("div",null,[...e[0]||(e[0]=[l('<h1 id="alineacion" tabindex="-1">Alineación <a class="header-anchor" href="#alineacion" aria-label="Permalink to &quot;Alineación&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>La alineación es el proceso de posicionar componentes conectados de modo que sus ejes, centros o puntos de referencia estén correctamente emparejados.</p><p>Es especialmente crítica en equipo rotativo donde los ejes deben alinearse para transmitir potencia eficientemente y evitar esfuerzo mecánico.</p><p>La alineación adecuada asegura una operación suave y reduce el desgaste.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de la alineación es asegurar que los componentes conectados operen sin introducir fuerzas o vibración innecesarias.</p><p>Esto ayuda a:</p><ul><li>Reducir el esfuerzo mecánico en los componentes</li><li>Extender la vida útil del equipo</li><li>Mejorar la eficiencia y el rendimiento</li><li>Prevenir fallas prematuras</li></ul><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>La alineación implica ajustar la posición del equipo para que las partes conectadas estén correctamente orientadas.</p><p>En sistemas rotativos, esto típicamente significa alinear ejes en términos de:</p><ul><li>Alineación angular, donde los ejes son paralelos</li><li>Alineación de desplazamiento, donde los centros están en la misma línea</li></ul><p>Los ajustes se realizan mediante:</p><ul><li>Calzas o ajuste de superficies de montaje</li><li>Movimiento del equipo horizontal o verticalmente</li><li>Uso de herramientas de medición como indicadores de carátula o sistemas de alineación láser</li></ul><p>La alineación debe verificarse bajo condiciones reales de instalación.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>La alineación es crítica en:</p><ul><li>Instalaciones de motores y bombas</li><li>Cajas de engranajes y sistemas de accionamiento</li><li>Equipo rotativo acoplado</li><li>Sistemas de transportadores</li><li>Cualquier sistema con partes rotativas conectadas</li></ul><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li>Las tolerancias de alineación dependen del tipo de equipo y la velocidad</li><li>La expansión térmica puede afectar la alineación durante la operación</li><li>La estabilidad de la cimentación influye en la alineación con el tiempo</li><li>La desalineación aumenta la vibración y la pérdida de energía</li><li>Puede requerirse verificación regular en sistemas críticos</li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>La desalineación es una causa común de fallas en rodamientos y acoplamientos</li><li>La alineación de precisión reduce la frecuencia de mantenimiento</li><li>Vuelva a verificar la alineación después del apriete y durante la puesta en marcha</li><li>Las condiciones de pie blando pueden afectar la precisión de la alineación</li><li>Siempre alinee bajo condiciones cercanas a la operación real</li></ul>',23)])])}const h=a(o,[["render",s]]);export{m as __pageData,h as default};
